// build/tools/gitlabGetFile.js
var gitlabGetFileSchema = {
  name: "gitlab_get_file",
  description: "Read a single file from a GitLab repository. Returns the decoded text content.",
  inputSchema: {
    type: "object",
    properties: {
      project: {
        type: "string",
        description: "Project in format 'namespace/project' or full URL"
      },
      path: {
        type: "string",
        description: "File path relative to repository root (e.g. 'src/index.ts')"
      },
      ref: {
        type: "string",
        description: "Optional: Branch, tag, or commit SHA. Defaults to the project's default branch"
      }
    },
    required: ["project", "path"]
  }
};
async function handleGitlabGetFile(args) {
  const { project, path: filePath, ref } = args;
  const projectPath = parseProject(project);
  const gl = getClient();
  const file = await gl.RepositoryFiles.show(projectPath, filePath, ref || "HEAD");
  const decoded = Buffer.from(file.content, "base64").toString("utf-8");
  const refInfo = ref ? ` (ref: ${ref})` : "";
  return {
    content: [
      {
        type: "text",
        text: `File: ${projectPath}/${filePath}${refInfo}
Size: ${file.size} bytes
SHA: ${file.content_sha256}

${decoded}`
      }
    ]
  };
}

// build/tools/gitlabGetFiles.js
var gitlabGetFilesSchema = {
  name: "gitlab_get_files",
  description: "Read multiple files from a GitLab repository in a single call. Returns decoded text content for each file.",
  inputSchema: {
    type: "object",
    properties: {
      project: {
        type: "string",
        description: "Project in format 'namespace/project' or full URL"
      },
      paths: {
        type: "array",
        items: { type: "string" },
        description: "Array of file paths relative to repository root"
      },
      ref: {
        type: "string",
        description: "Optional: Branch, tag, or commit SHA. Defaults to the project's default branch"
      }
    },
    required: ["project", "paths"]
  }
};
async function handleGitlabGetFiles(args) {
  const { project, paths, ref } = args;
  const projectPath = parseProject(project);
  const gl = getClient();
  const refInfo = ref ? ` (ref: ${ref})` : "";
  const results = await Promise.allSettled(paths.map(async (filePath) => {
    const file = await gl.RepositoryFiles.show(projectPath, filePath, ref || "HEAD");
    const decoded = Buffer.from(file.content, "base64").toString("utf-8");
    return {
      path: filePath,
      size: file.size,
      sha: file.content_sha256,
      content: decoded
    };
  }));
  const sections = [];
  let successCount = 0;
  let errorCount = 0;
  for (const result of results) {
    if (result.status === "rejected") {
      errorCount++;
      sections.push(`--- ERROR ---
${result.reason}`);
    } else {
      successCount++;
      const val = result.value;
      sections.push(`--- ${val.path} (${val.size} bytes, sha: ${val.sha}) ---
${val.content}`);
    }
  }
  const summary = `Fetched ${successCount}/${paths.length} files from ${projectPath}${refInfo}${errorCount > 0 ? ` (${errorCount} errors)` : ""}`;
  return {
    content: [
      {
        type: "text",
        text: `${summary}

${sections.join("\n\n")}`
      }
    ]
  };
}

// build/tools/gitlabCreateReview.js
var gitlabCreateReviewSchema = {
  name: "gitlab_create_review",
  description: "Create a merge request review by posting inline discussion threads on specific lines of code. Optionally approve or unapprove the MR.",
  inputSchema: {
    type: "object",
    properties: {
      project: {
        type: "string",
        description: "Project in format 'namespace/project' or full URL"
      },
      mrIid: {
        type: "string",
        description: "Merge request IID"
      },
      approve: {
        type: "boolean",
        description: "Whether to approve the MR after posting comments (default: false)"
      },
      body: {
        type: "string",
        description: "Optional: Top-level comment on the MR"
      },
      comments: {
        type: "array",
        description: "Inline comments to attach to specific lines",
        items: {
          type: "object",
          properties: {
            path: {
              type: "string",
              description: "File path relative to repo root"
            },
            line: {
              type: "number",
              description: "Line number (new file side)"
            },
            body: {
              type: "string",
              description: "Comment text (supports markdown)"
            }
          },
          required: ["path", "line", "body"]
        }
      }
    },
    required: ["project", "mrIid", "comments"]
  }
};
async function handleGitlabCreateReview(args) {
  const { project, mrIid, approve = false, body, comments } = args;
  const projectPath = parseProject(project);
  const gl = getClient();
  const iid = parseInt(mrIid);
  if (body) {
    await gl.MergeRequestNotes.create(projectPath, iid, body);
  }
  const mr = await gl.MergeRequests.show(projectPath, iid);
  const { base_sha, head_sha, start_sha } = mr.diff_refs;
  for (const comment of comments || []) {
    await gl.MergeRequestDiscussions.create(projectPath, iid, comment.body, {
      position: {
        baseSha: base_sha,
        headSha: head_sha,
        startSha: start_sha,
        positionType: "text",
        newPath: comment.path,
        newLine: String(comment.line)
      }
    });
  }
  if (approve) {
    await gl.MergeRequestApprovals.approve(projectPath, iid);
  }
  return {
    content: [
      {
        type: "text",
        text: `Review posted on MR !${mrIid}${approve ? " (approved)" : ""}

Inline comments: ${(comments || []).length}${body ? "\nTop-level comment: posted" : ""}`
      }
    ]
  };
}

